```class Solution {
    public int maxScore(String s) {
        int n = s.length();
        int leftZeros = 0, rightOnes = 0;
        for (int i = 0; i < n - 1; i++) {
            if (s.charAt(i) == '0') leftZeros++;
            if (s.charAt(n - i - 1) == '1') rightOnes++;
        }
        int maxScore = leftZeros + rightOnes;
        for (int i = 0; i < n - 1; i++) {
            if (s.charAt(i) == '0') leftZeros--;
            if (s.charAt(n - i - 1) == '1') rightOnes++;
            maxScore = Math.max(maxScore, leftZeros + rightOnes);
        }
        return maxScore;
    }
}```
